var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"OPR_NPC_NULL_NULL","text":{"KOREA":"그림자 토벌 확인. 사냥 종료.","JPN":"シャドウ討伐確認。狩りは終了です。","ENG":"Shadow exterminated. The hunt has ended.","TWN":"暗影討伐完畢，狩獵結束。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"OPR_NPC_NULL_NULL","text":{"KOREA":"함선에 복귀하시는대로 현실 부상을 개시하겠습니다.","JPN":"艦船に復帰されましたら、すぐに現実への浮上を開始します。","ENG":"Reemergence to the Normalside will commence as soon as you return to the ship.","TWN":"在你返回艦船後，本艦將立即向現世躍出。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":"추격전을 다섯 번이나 치르게 만들다니. 끈질긴 녀석이군.","JPN":"5回も追撃戦をやらせるとは、しつこい奴だ。","ENG":"Making us chase after it five times. Persistent, much?","TWN":"竟然讓我們追了五次，真是個頑固的傢伙。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":"시렌 전대가 아니었다면 이번에도 놓치고 말았겠지.","JPN":"シレン戦隊の協力がなければ、今回も見逃していただろう。","ENG":"If it weren't for Sirin Division, we would've let it get away again.","TWN":"如果不是賽蓮小隊，這次也會錯過的吧。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":"고생 많았다, 율리아.","JPN":"ご苦労だった、ユリア。","ENG":"Great work, Yulia.","TWN":"辛苦了，茱莉亞。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"그러게요… 간신히 잡았어요.","JPN":"そうですね……なんとか捕まえました。","ENG":"Yes... We barely caught it.","TWN":"是啊……好不容易才逮到的。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"제가 저희 대원들처럼 카운터였다면, 고생을 좀 덜었을 텐데 말이죠.","JPN":"隊員たちのように私もカウンターだったら……もう少し楽にできたんでしょうけど。","ENG":"If I was also a Counter like the rest of our members, maybe it would've been easier.","TWN":"如果我像我們的隊員們一樣是制裁者的話，可能就不會這麼辛苦了。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"힐데 씨.","JPN":"ヒルデさん。","ENG":"Miss Hilde?","TWN":"希爾德。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":"왜 그러지?","JPN":"なんだ？","ENG":"What is it?","TWN":"怎麼了？"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"이 그림자가 이런 특이한 검을 갖고 있던데… 혹시 알아보시겠어요?","JPN":"このシャドウ、変わった剣を持っていましたが……ヒルデさんはこれが何かわかりますか？","ENG":"This Shadow had this strange-looking sword... Do you recognize it?","TWN":"這個暗影拿著這樣一把特別的劍……你認得它嗎？"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":"이건…? 울브즈베인?","JPN":"これは……？　ウルブズベイン？","ENG":"That's...? Wolvesbane?","TWN":"這是……？狼之災禍？"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":"아니, 그럴 리 없지. 이 검이 두 자루가 존재할 리는 없으니까.","JPN":"いや、まさか……この剣が2本も存在するはずがない。","ENG":"No, it can't be. There is no way two of these swords exist.","TWN":"不，不可能。這把劍不可能有兩把。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"그런가요?","JPN":"そうですか？","ENG":"Really?","TWN":"是嗎？"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"만약… 이 그림자가… 우리가 알던 그 늑대일 수도 있지 않겠어요?","JPN":"もしかすると……このシャドウが、私たちの知っているあのオオカミの可能性もあるのでは？","ENG":"Then... could this Shadow... be the Wolf we knew?","TWN":"如果說……這個暗影……就是我們認識的那隻狼，這可能嗎？"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":"늑대가 둘일 수는 없다.","JPN":"オオカミが2人存在する可能性はない。","ENG":"There can't be two Wolves.","TWN":"狼不可能有兩個。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":"왜 그런 터무니없는 얘길 하는지 모르겠군.","JPN":"なぜそんな突拍子もないことを言うんだ？","ENG":"I don't see why you are talking such nonsense.","TWN":"真搞不懂你為什麼會說出這麼荒謬的話。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"…역시 그렇죠?","JPN":"……やはり、そうですよね。","ENG":"…You're right.","TWN":"……你說的沒錯。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"못 들은 걸로 해주세요.","JPN":"今のは聞かなかったことにしてください。","ENG":"Please, just ignore me.","TWN":"請當作沒聽到吧。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"이면세계에 오래 머물렀더니 머리가 이상해졌나 봐요.","JPN":"裏世界に長居したせいで、頭がどうにかなったようです。","ENG":"Maybe my head was in the clouds after being in the Counterside for too long.","TWN":"在異界待久了，腦子好像有點不正常了。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":null,"text":{"KOREA":"어떻습니까?","JPN":"どうですか？","ENG":"So?","TWN":"如何？"},"stage":{"bg":"SKY_NIGHT","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":null,"text":{"KOREA":"진실을 알고서 이면의 것들을 마주하게 된 소감은?","JPN":"真実を知って、裏世界の存在に向き合った感想は？","ENG":"How does it feel to know the truth and see what is on the other side?","TWN":"知道真相後，面對異界的事物有什麼感想？"},"stage":{"bg":"SKY_NIGHT","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"…네. 이제야 알겠어요.","JPN":"……はい。やっとわかりました。","ENG":"...Yes. I understand now.","TWN":"……是的。現在我明白了。"},"stage":{"bg":"SKY_NIGHT","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"그 수많은 그림자들에게서 느낀 기시감은… 착각이 아니었군요.","JPN":"あの数えきれないシャドウたちから感じた既視感は……私の勘違いではなかった。","ENG":"The sense of deja vu I felt from those countless Shadows... I wasn't mistaken.","TWN":"從那些無數的暗影中感受到的似曾相識感……果然不是錯覺。"},"stage":{"bg":"SKY_NIGHT","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"이런 식으로… 옛 세계에 남겨진 전우들을 몇 번씩이고 제 손으로 죽이고 있었던 거네요.","JPN":"こうして私は……旧世界に残された戦友たちを、何度も手にかけてきたのですね。","ENG":"I've been killing the comrades left behind in the old world again and again, with my own hands...","TWN":"就這樣……我一次又一次地親手殺死了留在舊世界的戰友們。"},"stage":{"bg":"SKY_NIGHT","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"왼쪽 팔이 없었던 그 그림자는… 부전대장 타티아나.","JPN":"左腕がなかったあのシャドウは……副戦隊長のタテイアナ。","ENG":"The Shadow that had no left arm... That was Deputy Commander Tatiana.","TWN":"缺了左臂的那個暗影是……副戰隊長塔蒂亞娜。"},"stage":{"bg":"MS_1302","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};